import{_ as t,o,c as n,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"70. Union Matters","description":"","frontmatter":{"title":"70. Union Matters","eba":"Health Allied & Managers Admin 2021-2025","topics":["union-matters"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/union-matters/70-union-matters.md","filePath":"ebas/has-managers-admin/common-terms/union-matters/70-union-matters.md"}'),r={name:"ebas/has-managers-admin/common-terms/union-matters/70-union-matters.md"};function s(i,e,l,p,m,c){return o(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="_70-union-matters" tabindex="-1">70. Union Matters <a class="header-anchor" href="#_70-union-matters" aria-label="Permalink to &quot;70. Union Matters&quot;">​</a></h1><p><strong>70.1</strong> Access to Employees – General The HWU will have access to Employees for any process arising under this Agreement.</p><p><strong>70.2</strong> Access to Employees – Electronic communication The Employer will ensure that:</p><p><strong>(a)</strong> emails from the HWU domain name are not blocked or restricted by or on behalf of the Employer, except in respect of any individual Employee who has made a written request to the Employer to block such emails;</p><p><strong>(b)</strong> emails from Employees to the HWU are not blocked or restricted by or on behalf of the Employer;</p><p><strong>(c)</strong> access from health service computers and like devices to HWU websites and online information is not blocked, or limited; and</p><p><strong>(d)</strong> where a genuine security concern arises regarding the above, the Employer will immediately notify the HWU to enable the security concern to be addressed.</p><p><strong>70.3</strong> Access to Employees – Orientation/Induction</p><p><strong>(a)</strong> The HWU may attend, address and provide information to new Employees as part of orientation/induction programs for new Employees. The details of such attendance will be arranged by the Employer in consultation with the HWU.</p><p><strong>(b)</strong> Any attendance for the purposes of discussions with the Employees must meet the right of entry requirements under Part 3-4 of the Act.</p><p><strong>(c)</strong> An Employer will advise the HWU of the date, time and location of orientation/induction programs not less than 14 days prior to the orientation/induction program.</p><p><strong>(d)</strong> Those covered by this Agreement acknowledge the increasing role that technology plays in orientation / induction. Where an Employer conducts online orientation/induction, the Employer shall provide to the HWU alternative means by which the HWU can access new Employees, provided that such access is consistent with this subclause 70.3.</p><p><strong>70.4</strong> Delegates and HSRs NOTE: Additional rights of HSRs are contained in the OHS Act.</p><p><strong>(a)</strong> In this subclause 70.4(a) Representative means a HWU Delegate, or HSR.</p><p><strong>(b)</strong> A Representative is entitled to reasonable time release from duty to:</p><p><strong>(i)</strong> attend to matters relating to industrial, occupational health and safety or other relevant matters such as assisting with grievance procedures, attending committee meetings and facilitating posting to noticeboards in secure areas (subject to occupational health and safety or other reasonable requirements of the Employer);</p><p><strong>(ii)</strong> access reasonable preparation time before meetings with management disciplinary or grievance meetings with a HWU member;</p><p><strong>(iii)</strong> appear as a witness or participate in conciliation or arbitration, before the Commission;</p><p><strong>(iv)</strong> present information on the HWU at orientation sessions for new Employees.</p><p><strong>(c)</strong> A Representative required to attend management or consultative meetings outside of paid time will be paid to attend.</p><p><strong>(d)</strong> A Representative will be provided with access to facilities such as telephones, computers, email, noticeboards and meeting rooms in a manner that does not adversely affect service delivery and work requirements of the Employer. In the case of an HSR, facilities will</p><p>include other facilities as necessary to enable them to perform their functions as prescribed under the OHS Act.</p><p><strong>70.5</strong> Noticeboard</p><p><strong>(a)</strong> A noticeboard for the HWU’s use will be readily accessible in each ward/unit/work area where persons eligible to be members of the HWU are employed, unless otherwise agreed by the AIC referred to in subclause 70.10.</p><p><strong>(b)</strong> The HWU and members covered by this Agreement will, during the life of this Agreement, consult over the development of an electronic noticeboard managed by the HWU.</p><p><strong>(c)</strong> Where an Employer cannot facilitate noticeboards pursuant to subclause 70.5(a) as they operate in a building that is not owned by the Employer, the Employer and HWU will, as soon as reasonably practicable, implement an electronic noticeboard or other mutually agreed arrangement to give effect to subclause 70.5(a); this may include, but is not limited to:</p><p><strong>(i)</strong> Centralised noticeboard(s) (e.g. a noticeboard in the staff cafeteria, but not in each ward/unit/work area);</p><p><strong>(ii)</strong> The Employer providing a link on the staff intranet page that directs staff to the HWU website;</p><p><strong>(iii)</strong> Additional reasonable time release for Representatives to attend to industrial matters associated with distributing Union communications that otherwise would be placed on noticeboards.</p><p><strong>(d)</strong> Where discussions referred to in 70.5(c) are unsuccessful, either party may refer the matter to the Fair Work Commission in accordance with <a href="/eba/ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.html">Clause 17</a> – Dispute Resolution</p><p><strong>70.6</strong> Meeting Space In the absence of agreement on a location for the holding of HWU meetings, the room where one or more of the Employees who may participate in the meeting ordinarily take meal or other breaks will be the meeting room for the purpose of HWU meetings. Nothing in this clause is intended to override the operation of the Act.</p><p><strong>70.7</strong> Secondment to the HWU The Employer will, on application, grant leave without pay to an Employee for the purpose of secondment to work for the HWU subject to the Employer’s reasonable operational requirements.</p><p><strong>70.8</strong> Employees holding HWU official positions The Employer will, on application by the HWU, grant leave without loss of pay (including reasonable travelling time) to an Employee for the purpose of</p><p>fulfilling their duties as an official of the HWU Branch Committee of Management or HWU delegate to the Health Services HWU National Council. For a member of the HWU Branch Committee of Management this currently involves 11 full day meetings per year.</p><p><strong>70.9</strong> Union Training NOTE: an HSR may be entitled to any training in accordance with the OHS Act rather than, or in addition to, this clause.</p><p><strong>(a)</strong> Subject to the conditions in this subclause 70.9, Employees selected by the HWU to attend training courses on industrial relations and/or health and safety will be entitled to a maximum of five days’ paid leave per calendar year per Employee.</p><p><strong>(b)</strong> Leave in excess of five days and up to ten days may be granted in a calendar year subject to the total leave being granted in that year and in the subsequent year not exceeding ten days.</p><p><strong>(c)</strong> The granting of leave will be subject to the Employer’s operational requirements. The granting of leave will not be unreasonably withheld.</p><p><strong>(d)</strong> Leave under this subclause is granted on the following conditions:</p><p><strong>(i)</strong> applications are accompanied by a statement from the HWU advising that it has nominated the Employee or supports the application:</p><p><strong>(ii)</strong> the training is conducted by the HWU, an association of unions or accredited training provider; and</p><p><strong>(iii)</strong> the application is made as early as practicable and not less than two (2) weeks before the training.</p><p><strong>(e)</strong> The Employee will be paid their ‘ordinary pay’ (as defined at clause 53.6(b)(Annual Leave)) for normal rostered hours (set out in <a href="/eba/ebas/has-managers-admin/schedules/2b-wage-rates-health-allied-services.html">Schedules 2B</a> and 3B), but excluding shift work, overtime and other allowances.</p><p><strong>(f)</strong> Leave in accordance with this clause may include necessary travelling time in normal hours immediately before or after the course.</p><p><strong>(g)</strong> Leave granted under this clause will count as service for all purposes of this Agreement.</p><p><strong>(h)</strong> Expenses associated with attendance at training courses, including fares, accommodation and meal costs are not the responsibility of the Employer.</p><p><strong>70.10</strong> Agreement Implementation Committees</p><p><strong>(a)</strong> A local agreement implementation committee (AIC) will continue or, if there is not currently an AIC in operation, be established at each</p><p>Employer. Having regard for the size and location, an AIC may be appropriate at each facility/campus. The AIC will, where practicable, comprise equal numbers of representatives of the Employer and the HWU for the purposes of:</p><p><strong>(i)</strong> agreement implementation;</p><p><strong>(ii)</strong> on-going monitoring and assessment of the implementation of this Agreement; and</p><p><strong>(iii)</strong> to deal with any local disputes that may arise, without limiting the Dispute Resolution Procedure in this Agreement.</p><p><strong>(b)</strong> Priority items for consideration by the AIC will include the matters arising under:</p><p><strong>(i)</strong> Union Matters (Section 1, Clause 70)</p><p><strong>(ii)</strong> Designated Working Groups (Section 1, <a href="/eba/ebas/has-managers-admin/common-terms/ohs/80-occupational-health-safety.html">Clause 80.2</a>)</p><p><strong>(iii)</strong> Transition to New Instrument Technician Structure (Section 2, <a href="/eba/ebas/has-managers-admin/common-terms/allowances/37-lead-apron-allowance.html">Clause 37</a>)</p><p><strong>(iv)</strong> Transition to New Theatre Technician Structure (Section 2, <a href="/eba/ebas/has-managers-admin/common-terms/wages/35-juniors.html">Clause 35</a>)</p><p><strong>(v)</strong> Transition of All Other Employees (Section 2, <a href="/eba/ebas/has-managers-admin/common-terms/wages/36-employee-records.html">Clause 36</a>)</p><p><strong>(vi)</strong> Introduction of Revised Food Services Classification Structure (Section 2, <a href="/eba/ebas/has-managers-admin/common-terms/allowances/37-lead-apron-allowance.html">Clause 37</a>)</p><p><strong>(vii)</strong> Introduction of Revised General Services Classification Structure (Section 2, <a href="/eba/ebas/has-managers-admin/common-terms/allowances/38-supported-wage-system-for-employees-with-a.html">Clause 38</a>)</p><p><strong>(viii)</strong> Introduction of Revised Pathology Collector Structure (Section 2, <a href="/eba/ebas/has-managers-admin/common-terms/allowances/39-meal-allowances.html">Clause 39</a>)</p><p><strong>(ix)</strong> Introduction of Revised Allied Health Assistant Classification Structure (Section 2, <a href="/eba/ebas/has-managers-admin/common-terms/allowances/40-telephone-allowance.html">Clause 40</a>)</p><p><strong>(x)</strong> Introduction of Revised Health Care Worker Classification Structure (Section 2, <a href="/eba/ebas/allied-health/allowances/41-travelling-allowance.html">Clause 41</a>)</p><p><strong>(xi)</strong> Introduction of Lifestyle Assistant and Complimentary Therapies Worker Structure (Section 2, <a href="/eba/ebas/has-managers-admin/common-terms/allowances/44-on-call-recall.html">Clause 44</a>)</p><p><strong>70.11</strong> Secondment to the HWU</p><p><strong>(a)</strong> The Employer will, on application, grant leave without pay to an Employee for the purpose of secondment to work for the HWU subject to the Employer’s reasonable operational requirements.</p><p><strong>(b)</strong> The Employee’s application must set out:</p><p><strong>(i)</strong> the period of leave without pay sought – which must not exceed a period of twelve (12) months; and,</p><p><strong>(ii)</strong> the Employee recognises that the Employee may not be able to return to their substantive role earlier than the requested end date.</p><p><strong>(iii)</strong> Where an Employee seeks to extend their secondment beyond a period of twelve months, the Employee must submit a new application to their Employer no less than six- weeks prior to the end of their current secondment arrangement.</p><p><strong>(c)</strong> Where an Employee is seconded in accordance with this clause:</p><p><strong>(i)</strong> the Employee’s absence will not contribute to, but not break continuity of service for the purpose of: <strong>(A)</strong> Long Service Leave (<a href="/eba/ebas/has-managers-admin/common-terms/leave/61-long-service-leave.html">Clause 61</a>); <strong>(B)</strong> Notice of Termination – Employer (<a href="/eba/ebas/allied-health/preliminary/5-incidence-coverage.html">Clause 5</a> of Section 2 and <a href="/eba/ebas/has-managers-admin/common-terms/preliminary/3-arrangement-of-the-agreement.html">Clause 3</a> of Section 3) and <strong>(C)</strong> Redundancy and Associated Entitlements (<a href="/eba/ebas/has-managers-admin/common-terms/employment-types/26-redundancy-and-associated-entitlements.html">Clause 26</a>)</p><p><strong>(ii)</strong> An Employee who possesses an ongoing contract of employment will return to their pre-secondment contracted hours of work at the cessation of the secondment arrangement.</p><p><strong>(iii)</strong> An Employer will not be required to return to the Employee to their substantive role earlier than the requested end date.</p><p><strong>(iv)</strong> The Employee will be expected to maintain confidentiality on matters pertaining to their substantive work with the Employer and the secondment with the HWU.</p><p><strong>(v)</strong> The Employer and the Union will not require the Employee to divulge information that may cause the Employee to breach subclause 70.11(c)(iv).</p><p>Plain language terms: union rep, delegate, union representative, right of entry.</p>',77)])])}const g=t(r,[["render",s]]);export{d as __pageData,g as default};
